import './LinearProgress.scss';

import type { FC } from 'react';
import React, { useMemo } from 'react';

import { classNames } from '../../../helpers/classnames';
import type { LinearProgressProps } from './LinearProgress.types';

export const LinearProgress: FC<LinearProgressProps> = ({
	value = 0,
	type = 'solo',
	cycled = false,
	className,
	style,
	...props
}) => {
	const limitedValue = useMemo(() => Math.min(value, 100), [value]);
	const progressBarTransform = useMemo(() => `${limitedValue}%`, [limitedValue]);

	return (
		<span
			data-testid="LinearProgress"
			{...props}
			style={{ ...style }}
			className={classNames('dsb_progress', 'dsb_progress__linear', `dsb_progress__linear-${type}`, className)}
			role="progressbar"
			aria-valuenow={value}
			aria-valuemax={100}
			aria-valuemin={0}
		>
			<span
				style={{ width: progressBarTransform }}
				className={classNames('dsb_progress-bar', cycled && 'dsb_progress-bar__cycled', `dsb_progress-bar__${type}`)}
			/>
		</span>
	);
};
